#include <bits/stdc++.h>
using namespace std;
string s1;
int ans,x,y,dx[]={0,0,0,1,-1},dy[]={0,1,-1,0,0};
map<string,bool> mp;
struct node
{
	string s;
	int x,y,step;
};
int fun(int _x,int _y)
{
	return (_x)*3+(_y);
}
bool check(int _x,int _y)
{
	if(_x>2||_x<0||_y>2||_y<0) return 1;
	return 0;
}
void bfs()
{
	queue<node> q;
	q.push(node{s1,x,y,0});
	while(!q.empty())
	{
		node t=q.front();
		q.pop();
		if(t.s=="123804765")
		{
			ans=t.step;
			return ;
		}
		for(int i=1;i<=4;i++)
		{
			int nx=t.x+dx[i];
			int ny=t.y+dy[i];
			string ns=t.s;
			swap(ns[fun(nx,ny)],ns[fun(t.x,t.y)]);
			if(check(nx,ny)||mp.count(ns)) continue;
			mp[ns]=1;
			q.push(node{ns,nx,ny,t.step+1});
		}
	}
}
int main()
{
	cin>>s1;
	for(int i=0;i<9;i++)
	{
		if(s1[i]=='0') x=(i/3),y=(i%3);
	}
	bfs();
	cout<<ans;
	return 0;
}
